import { useState } from "react";
import { useSpeechRecognition, useTTS } from "../../hooks/useSpeech";

export default function ConversationSection({ conversation, onDone, done }) {
  console.log(done);
  const { speak } = useTTS();
  const { listening, transcript, error, startListening, stopListening, reset } =
    useSpeechRecognition();
  const [stepIdx, setStepIdx] = useState(0);
  const [userReplies, setUserReplies] = useState({});
  const [typedInput, setTypedInput] = useState("");
  const [mode, setMode] = useState("type"); // "type" | "mic"
  const [finished, setFinished] = useState(false);

  const steps = conversation?.steps;
  const current = steps[stepIdx];

  function submitReply(text) {
    if (!text.trim()) return;
    setUserReplies((r) => ({ ...r, [stepIdx]: text }));
    reset();
    setTypedInput("");
    if (stepIdx + 1 < steps.length) setStepIdx((i) => i + 1);
    else setFinished(true);
  }

  function handleMic() {
    if (listening) {
      stopListening();
    } else {
      reset();
      startListening();
    }
  }

  if (finished) {
    return (
      <div className="fade-in">
        <div className="text-center py-6">
          <div className="text-5xl mb-3">🤝</div>
          <h3 className="font-playfair text-xl text-blue-900 mb-2">
            Great Conversation!
          </h3>
          <p className="text-sm text-slate-500">
            You completed the conversation practice!
          </p>
        </div>
        <div className="bg-slate-50 border border-slate-200 rounded-2xl p-4 space-y-3 mb-4">
          <p className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">
            Full Conversation
          </p>
          {steps.map((s, i) => (
            <div
              key={i}
              className={`flex ${s.speaker === "user" ? "justify-end" : "justify-start"}`}
            >
              <div
                className={`max-w-[75%] px-4 py-2.5 rounded-2xl text-sm font-bold shadow-sm
                ${
                  s.speaker === "app"
                    ? "bg-blue-900 text-white rounded-bl-sm"
                    : "bg-white border-2 border-pink-200 text-slate-800 rounded-br-sm"
                }`}
              >
                {s.speaker === "app" ? s.text : userReplies[i] || "(no reply)"}
              </div>
            </div>
          ))}
        </div>
        {!done ? (
          <div className="flex justify-end">
            <button
              onClick={onDone}
              className="bg-blue-900 hover:bg-blue-800 text-white font-bold px-8 py-3 rounded-xl text-sm transition-all hover:-translate-y-0.5"
            >
              Complete ✓
            </button>
          </div>
        ) : (
          <p className="text-right text-green-700 font-bold text-sm">
            ✓ Conversation completed!
          </p>
        )}
      </div>
    );
  }

  console.log(conversation)
  console.log(current?.speaker);
  console.log(steps);
  return (
    <div className="fade-in">
      <div className="bg-gradient-to-br from-teal-50 to-cyan-50 border-2 border-teal-100 rounded-2xl p-4 mb-4">
        <p className="text-xs font-bold text-teal-700 mb-0.5">Scenario:</p>
        <p className="text-sm font-extrabold text-slate-800">
          {conversation.scenario}
        </p>
      </div>

      {/* Chat bubbles so far */}
      <div className="space-y-3 mb-4 max-h-60 overflow-y-auto px-1">
        {steps?.slice(0, stepIdx + 1).map((s, i) => {
          if (i > stepIdx) return null;
          const isApp = s?.speaker === "app";
          const isUser = s?.speaker === "user";
          const isCurrentUser = isUser && i === stepIdx;
          return (
            <div
              key={i}
              className={`flex ${isApp ? "justify-start" : "justify-end"} fade-in`}
            >
              {isApp && (
                <div className="max-w-[75%] bg-blue-900 text-white px-4 py-2.5 rounded-2xl rounded-bl-sm text-sm font-bold shadow-sm">
                  {s.text}
                  <button
                    onClick={() => speak(s.text)}
                    className="ml-2 text-blue-200 hover:text-white text-xs"
                  >
                    🔊
                  </button>
                </div>
              )}
              {isUser && !isCurrentUser && (
                <div className="max-w-[75%] bg-white border-2 border-pink-200 text-slate-800 px-4 py-2.5 rounded-2xl rounded-br-sm text-sm font-bold shadow-sm">
                  {userReplies[i] || "(skipped)"}
                </div>
              )}
              {isCurrentUser && (
                <div className="max-w-[80%] bg-pink-50 border-2 border-pink-200 text-slate-600 px-4 py-2.5 rounded-2xl rounded-br-sm text-sm italic shadow-sm">
                  💭 {s.prompt}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Input area */}
      {current?.speaker === "user" && (
        <div className="bg-white border-2 border-slate-200 rounded-2xl p-4">
          <p className="text-xs font-bold text-slate-500 mb-3">
            Your turn: <span className="text-pink-600">{current.prompt}</span>
          </p>
          <div className="flex gap-2 mb-3">
            <button
              onClick={() => setMode("type")}
              className={`text-xs px-3 py-1.5 rounded-lg font-bold border-2 transition-all ${mode === "type" ? "bg-blue-900 text-white border-blue-900" : "bg-white text-slate-600 border-slate-200"}`}
            >
              ✍️ Type
            </button>
            <button
              onClick={() => setMode("mic")}
              className={`text-xs px-3 py-1.5 rounded-lg font-bold border-2 transition-all ${mode === "mic" ? "bg-blue-900 text-white border-blue-900" : "bg-white text-slate-600 border-slate-200"}`}
            >
              🎤 Speak
            </button>
          </div>
          {mode === "type" ? (
            <div className="flex gap-2">
              <input
                className="flex-1 px-3 py-2 border-2 border-slate-200 rounded-xl text-sm font-bold focus:outline-none focus:border-blue-900 transition-all"
                placeholder="Type your reply in English..."
                value={typedInput}
                onChange={(e) => setTypedInput(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && submitReply(typedInput)}
              />
              <button
                onClick={() => submitReply(typedInput)}
                className="bg-blue-900 text-white px-5 py-2 rounded-xl font-bold text-sm hover:bg-blue-800 transition-all"
              >
                Send →
              </button>
            </div>
          ) : (
            <div>
              <div className="flex items-center gap-3 mb-3">
                <button
                  onClick={handleMic}
                  className={`w-12 h-12 rounded-full flex items-center justify-center text-2xl border-4 transition-all shadow-lg
                    ${listening ? "bg-red-500 border-red-300 pulse-ring" : "bg-blue-900 border-blue-700 hover:scale-105"}`}
                >
                  🎤
                </button>
                <p className="text-sm font-bold text-slate-600">
                  {listening ? "🔴 Listening..." : "Click to speak"}
                </p>
              </div>
              {transcript && (
                <div className="bg-slate-50 border border-slate-200 rounded-xl p-3">
                  <p className="text-sm font-bold text-slate-800 mb-2">
                    "{transcript}"
                  </p>
                  <div className="flex gap-2">
                    <button
                      onClick={() => submitReply(transcript)}
                      className="text-xs bg-green-700 text-white px-4 py-1.5 rounded-lg font-bold hover:bg-green-600"
                    >
                      Use this ✓
                    </button>
                    <button
                      onClick={reset}
                      className="text-xs bg-slate-200 text-slate-600 px-4 py-1.5 rounded-lg font-bold hover:bg-slate-300"
                    >
                      Try again
                    </button>
                  </div>
                </div>
              )}
              {error && <p className="text-xs text-red-500 mt-1">{error}</p>}
            </div>
          )}
        </div>
      )}
    </div>
  );
}
